SELECT academic_year, AVG(enrolled) AS average_enrolled
FROM admissions
GROUP BY academic_year;

SELECT university_name
FROM universities
WHERE ranking > 15;

SELECT DISTINCT academic_year
FROM admissions
ORDER BY academic_year ASC;

SELECT AVG(enrolled) AS avg_enrollment_rate
FROM admissions
WHERE apps > (
    SELECT AVG(apps)
    FROM admissions
);

SELECT university_name, ranking
FROM universities
ORDER BY ranking DESC;

SELECT university_name, location
FROM universities
ORDER BY ranking DESC;

SELECT u.university_name, a.enrolled
FROM universities u
JOIN admissions a ON u.admission_id = a.admission_id;
